#include <stdio.h>
#include <stdlib.h>

// Function to calculate harmonic prefix sums and store them in an array
void computeHarmonicPrefixSums(int n, double *harmonicSums) {
    for (int i = 1; i <= n; i++) {
        harmonicSums[i - 1] = 0.0;
        for (int j = 1; j <= i; j++) {
            harmonicSums[i - 1] += 1.0 / j;
        }
    }
}

int main(void) {
    int n;
    printf("Enter the value of n: ");
    scanf("%d", &n);

    // Allocate memory for the array to store harmonic prefix sums
    double *harmonicSums = (double *)malloc(n * sizeof(double));
    if (harmonicSums == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    // Compute harmonic prefix sums and store them in the array
    computeHarmonicPrefixSums(n, harmonicSums);

    // Print all n values of the harmonic prefix sums
    for (int i = 0; i < n; i++) {
        printf("%.6f ", harmonicSums[i]);
    }
    printf("\n");

    // Free allocated memory
    free(harmonicSums);

    return 0;
}
